export function searchColleges(query) {
  if (!query || query.length < 2) return [];
  const q = query.toLowerCase();
  return INDIAN_COLLEGES
    .filter(c => c.name.toLowerCase().includes(q) || (c.state && c.state.toLowerCase().includes(q)))
    .slice(0, 10);
}

export function getDomainsForCollege(collegeName) {
  if (!collegeName) return [];
  const q = collegeName.toLowerCase();
  const match = INDIAN_COLLEGES.find(c => c.name.toLowerCase() === q || c.name.toLowerCase().includes(q));
  return match ? match.domains : [];
}
